<script>
    document.addEventListener('DOMContentLoaded', () => {
    const tabs = document.querySelectorAll('.tab');
    const tabProducts = document.getElementById('tab-products');
    const tabProtocol = document.getElementById('tab-protocol');

    function switchTab(activeTab) {
        tabs.forEach(t => t.classList.remove('active'));
        activeTab.classList.add('active');

        const isProtocol = activeTab.textContent.trim() === 'Протокол процедури';
        tabProducts.style.display = isProtocol ? 'none' : 'block';
        tabProtocol.style.display = isProtocol ? 'block' : 'none';
    }

    tabs.forEach(tab => tab.addEventListener('click', () => switchTab(tab)));

    // Set initial state based on which tab has 'active' class in HTML
    const initialActive = document.querySelector('.tab.active');
    if (initialActive) switchTab(initialActive);
});</script>

